const pdfParse = require('pdf-parse');
const buf = Buffer.from($json.file_data, 'base64');
const data = await pdfParse(buf);
return [{ json: { ...$json, pdf_text: data.text, page_count: data.numpages, text_for_metadata: data.text.substring(0, 6000), file_data: undefined } }];

const tenderId = $('trigger').first().json.tender_id;
const pdfText = $('extract-text').first().json.pdf_text;
const pageCount = $('extract-text').first().json.page_count;
const orgId = $('trigger').first().json.org_id;
const userId = $('trigger').first().json.user_id;
const sourceFilename = $('trigger').first().json.file_name || $('trigger').first().json.source_filename || '';

let metadata;
try {
  const aiContent = $json.choices[0].message.content;
  const cleaned = aiContent.replace(/```json/g, '').replace(/```/g, '').trim();
  metadata = JSON.parse(cleaned);
} catch (e) {
  metadata = { title: 'Unbekannte Ausschreibung', buyer: null, deadline: null, summary: null, region: null, category: null, tender_type: null };
}

return [{ json: {
  id: tenderId,
  org_id: orgId,
  user_id: userId,
  title: metadata.title || 'Unbekannte Ausschreibung',
  buyer: metadata.buyer || null,
  deadline: metadata.deadline || null,
  summary: metadata.summary || null,
  region: metadata.region || null,
  category: metadata.category || null,
  tendertype: metadata.tender_type || null,
  source_type: 'pdf',
  source_filename: sourceFilename,
  pdf_text: pdfText,
  page_count: pageCount,
  processing_status: 'metadata_ready'
} }];
